∀ {input : StructuralExhaustion.Graph.PackedMinimumDegreeCycle.StaticInput} {T : Type u} {boundaries : FinEnum T}
  [Nonempty T] {ctx : StructuralExhaustion.Core.MinimalCounterexampleContext input.problem input.Target}
  {atom :
    StructuralExhaustion.Graph.PackedBoundariedGluing.MinimumDegreeCycleReplacement.ProperAtom input boundaries ctx}
  (compression :
    StructuralExhaustion.Graph.PackedBoundariedGluing.MinimumDegreeCycleReplacement.Compression input boundaries atom),
  False

∀ {input : StructuralExhaustion.Graph.PackedMinimumDegreeCycle.StaticInput} {T : Type u} {boundaries : FinEnum T}
  [inst : Nonempty T] {ctx : StructuralExhaustion.Core.MinimalCounterexampleContext input.problem input.Target}
  {atom :
    StructuralExhaustion.Graph.PackedBoundariedGluing.MinimumDegreeCycleReplacement.ProperAtom input boundaries ctx}
  (compression :
    StructuralExhaustion.Graph.PackedBoundariedGluing.MinimumDegreeCycleReplacement.Compression input boundaries atom),
  compression.run.terminal = StructuralExhaustion.CT3.Graph.Terminal.compression

∀ {input : StructuralExhaustion.Graph.PackedMinimumDegreeCycle.StaticInput} {T : Type u} {boundaries : FinEnum T}
  [inst : Nonempty T] {ctx : StructuralExhaustion.Core.MinimalCounterexampleContext input.problem input.Target}
  {atom :
    StructuralExhaustion.Graph.PackedBoundariedGluing.MinimumDegreeCycleReplacement.ProperAtom input boundaries ctx}
  (compression :
    StructuralExhaustion.Graph.PackedBoundariedGluing.MinimumDegreeCycleReplacement.Compression input boundaries atom),
  compression.run.trace =
    [StructuralExhaustion.CT3.Graph.NodeId.entry, StructuralExhaustion.CT3.Graph.NodeId.vectorComputation,
      StructuralExhaustion.CT3.Graph.NodeId.compressionSearch,
      StructuralExhaustion.CT3.Graph.NodeId.compressionTerminal]

∀ {input : StructuralExhaustion.Graph.PackedMinimumDegreeCycle.StaticInput} {T : Type u} {boundaries : FinEnum T}
  [inst : Nonempty T] {ctx : StructuralExhaustion.Core.MinimalCounterexampleContext input.problem input.Target}
  {atom :
    StructuralExhaustion.Graph.PackedBoundariedGluing.MinimumDegreeCycleReplacement.ProperAtom input boundaries ctx}
  (compression :
    StructuralExhaustion.Graph.PackedBoundariedGluing.MinimumDegreeCycleReplacement.Compression input boundaries atom),
  compression.run.checks = 1

∀ {input : StructuralExhaustion.Graph.PackedMinimumDegreeCycle.StaticInput} {T : Type u} {boundaries : FinEnum T}
  [inst : Nonempty T] {ctx : StructuralExhaustion.Core.MinimalCounterexampleContext input.problem input.Target}
  {atom :
    StructuralExhaustion.Graph.PackedBoundariedGluing.MinimumDegreeCycleReplacement.ProperAtom input boundaries ctx}
  (compression :
    StructuralExhaustion.Graph.PackedBoundariedGluing.MinimumDegreeCycleReplacement.Compression input boundaries atom),
  compression.run.checks ≤
    (StructuralExhaustion.CT3.certifiedCompressionBudget ctx).coefficient *
      ((StructuralExhaustion.CT3.certifiedCompressionBudget ctx).size compression.certifiedInput + 1) ^
        (StructuralExhaustion.CT3.certifiedCompressionBudget ctx).degree

∀ {V : Type u} {object : StructuralExhaustion.Graph.FiniteObject V}
  (profile : StructuralExhaustion.Graph.PositiveDeficiencyWedge.Profile object),
  (∀ (vertex : V), 3 ≤ object.degree vertex) → profile.positiveDeficiency ≤ profile.boundaryIncidences

∀ {V : Type u} {object : StructuralExhaustion.Graph.FiniteObject V}
  (profile : StructuralExhaustion.Graph.PositiveDeficiencyWedge.Profile object),
  3 * profile.core.card ≤ profile.wedgeCount + 2 * profile.positiveDeficiency

∀ {V : Type u} {object : StructuralExhaustion.Graph.FiniteObject V}
  (profile : StructuralExhaustion.Graph.PositiveDeficiencyWedge.Profile object),
  3 * profile.core.card - 2 * profile.positiveDeficiency ≤ profile.wedgeCount

∀ {system : StructuralExhaustion.CT15.CertifiedDeterminationRank.System}
  (profile : StructuralExhaustion.CT15.CertifiedDeterminationRank.Profile system),
  profile.targetRank ≤ FinEnum.card system.Coordinate

∀ {family : StructuralExhaustion.CT15.FunctionalAdmissibleRank.Family}
  (profile : StructuralExhaustion.CT15.FunctionalAdmissibleRank.Profile family),
  profile.targetRank < FinEnum.card family.Coordinate ∨ profile.targetRank = FinEnum.card family.Coordinate

∀ {V : Type u} {residual : Internal.InitialResidual V} {node18 : Internal.Node18Stage residual}
  {bounded : Internal.Node19Low residual node18} {node21 : Internal.Node21Output node18 bounded}
  {low : Internal.Node22Low residual node18 bounded node21} {node31 : Internal.Node31Output node18 bounded node21 low}
  {rankDrop : Internal.Node32RankDrop node18}
  (node35 : Internal.Node35Output node18 bounded node21 low node31 rankDrop),
  ¬Internal.Node36OriginalUniversal node35 → Internal.Node36OriginalDefect node35

∀ {V : Type u} {residual : Internal.InitialResidual V} {node18 : Internal.Node18Stage residual}
  {bounded : Internal.Node19Low residual node18} {node21 : Internal.Node21Output node18 bounded}
  {low : Internal.Node22Low residual node18 bounded node21} {node31 : Internal.Node31Output node18 bounded node21 low}
  {rankDrop : Internal.Node32RankDrop node18}
  (node35 : Internal.Node35Output node18 bounded node21 low node31 rankDrop),
  ¬Internal.Node38AtOriginal node35 → Internal.Node38Enlarged node35

∀ {input : StructuralExhaustion.Graph.PackedMinimumDegreeCycle.StaticInput}
  {ctx : StructuralExhaustion.Core.MinimalCounterexampleContext input.problem input.Target} {Coordinate : Type v}
  {coordinateSupport : Coordinate → Finset ctx.G.Vertex} {coordinates : FinEnum Coordinate}
  {carrier : StructuralExhaustion.Graph.SupportStratifiedFunctionalRank.Carrier input ctx Coordinate}
  {proposal : StructuralExhaustion.Graph.SupportStratifiedFunctionalRank.Proposal input ctx Coordinate carrier},
  StructuralExhaustion.Graph.SupportStratifiedFunctionalRank.Admissible input ctx Coordinate coordinateSupport
      (StructuralExhaustion.Graph.SupportStratifiedFunctionalRank.declaredCoordinates Coordinate coordinates) proposal →
    StructuralExhaustion.Graph.SupportStratifiedDetermination.Interface.OriginalEligible carrier →
      Function.Injective proposal.code

∀ {input : StructuralExhaustion.Graph.PackedMinimumDegreeCycle.StaticInput}
  {ctx : StructuralExhaustion.Core.MinimalCounterexampleContext input.problem input.Target} {Coordinate : Type v}
  {coordinateSupport : Coordinate → Finset ctx.G.Vertex} {coordinates : FinEnum Coordinate}
  {carrier : StructuralExhaustion.Graph.SupportStratifiedFunctionalRank.Carrier input ctx Coordinate}
  {proposal : StructuralExhaustion.Graph.SupportStratifiedFunctionalRank.Proposal input ctx Coordinate carrier},
  StructuralExhaustion.Graph.SupportStratifiedFunctionalRank.Admissible input ctx Coordinate coordinateSupport
      (StructuralExhaustion.Graph.SupportStratifiedFunctionalRank.declaredCoordinates Coordinate coordinates) proposal →
    StructuralExhaustion.Graph.SupportStratifiedDetermination.Interface.IsWhole carrier →
      Function.Injective proposal.code

∀ {V : Type u} {residual : Internal.InitialResidual V} {node18 : Internal.Node18Stage residual}
  {_bounded : Internal.Node19Low residual node18} {node21 : Internal.Node21Output node18 _bounded}
  (self : Internal.Node49Output node18 _bounded node21),
  self.entropy = Real.logb 2 ↑self.stateCount / ↑(Internal.p13RemainderVertices (Internal.Node21Context node18)).card

